def safe_float(value: Any, default: float = 0.0) -> float:
    try:
        if value is None:
            return default
        out = float(value)
        if math.isnan(out) or math.isinf(out):
            return default
        return out
    except Exception:
        return default


def safe_div(a: float, b: float, default: float = 0.0) -> float:
    return a / b if abs(b) > 1e-12 else default


def pct(a: float, b: float) -> float:
    return safe_div(a, b, 1.0) - 1.0 if b else 0.0


def mean(values: Iterable[float]) -> float:
    xs = [safe_float(x) for x in values if x is not None]
    return sum(xs) / len(xs) if xs else 0.0


def stdev(values: Iterable[float]) -> float:
    xs = [safe_float(x) for x in values if x is not None]
    if len(xs) < 2:
        return 0.0
    centre = sum(xs) / len(xs)
    variance = sum((value - centre) * (value - centre) for value in xs) / len(xs)
    return math.sqrt(max(variance, 0.0))


def percentile(values: Sequence[float], q: float) -> float:
    xs = sorted(safe_float(x) for x in values if x is not None)
    if not xs:
        return 0.0
    if len(xs) == 1:
        return xs[0]
    pos = (len(xs) - 1) * min(max(q, 0.0), 1.0)
    lo = int(math.floor(pos))
    hi = int(math.ceil(pos))
    if lo == hi:
        return xs[lo]
    return xs[lo] + (xs[hi] - xs[lo]) * (pos - lo)


def sanitize_code(code: str) -> str:
    return "".join(ch for ch in code if ch.isalnum() or ch in "._-").upper()


def qfq_open_price(bar: "PriceBar") -> float:
    if bar.close > 0 and bar.qfq_close > 0 and bar.open > 0:
        return bar.open * safe_div(bar.qfq_close, bar.close, 1.0)
    return bar.qfq_close or bar.open or bar.close


def infer_latest_date(conn: sqlite3.Connection, code: str) -> str:
    row = conn.execute(
        "select max(trade_date) from stock_ohlcv_daily where ts_code=? and qfq_close>0",
        (code,),
    ).fetchone()
    if not row or not row[0]:
        raise RuntimeError(f"No OHLCV data found for {code}")
    return str(row[0])


