class PrefixSequence(Sequence[float]):
    """Read-only prefix view used to avoid copying full price history per bar."""

    def __init__(self, values: Sequence[float], end: int):
        self._values = values
        self._end = max(0, min(int(end), len(values)))

    def __len__(self) -> int:
        return self._end

    def __getitem__(self, key: Any) -> Any:
        if isinstance(key, slice):
            start, stop, step = key.indices(self._end)
            return self._values[start:stop:step]
        index = int(key)
        if index < 0:
            index += self._end
        if index < 0 or index >= self._end:
            raise IndexError(index)
        return self._values[index]

