class DataAgent:
    name = "DataAgent"

    def __init__(self, db_path: Path):
        self.db_path = Path(db_path)

    def load(self, code: str, as_of: Optional[str] = None) -> Tuple[List[PriceBar], Dict[str, Any]]:
        if not self.db_path.exists():
            raise FileNotFoundError(f"Database not found: {self.db_path}")
        conn = sqlite3.connect(str(self.db_path))
        if as_of is None or str(as_of).lower() == "latest":
            as_of = infer_latest_date(conn, code)
        rows = conn.execute(
            """
            select
              o.trade_date, o.ts_code, coalesce(o.stock_name, ''),
              o.open, o.high, o.low, o.close, o.qfq_close, o.pre_close,
              o.pct_chg, o.vol, o.amount, o.up_limit, o.down_limit,
              coalesce(o.suspend_timing, ''),
              coalesce(v.turnover_rate, 0), coalesce(v.turnover_rate_f, 0),
              coalesce(v.volume_ratio, 0),
              coalesce(m.net_mf_amount, 0), coalesce(m.buy_lg_amount, 0),
              coalesce(m.sell_lg_amount, 0), coalesce(m.buy_elg_amount, 0),
              coalesce(m.sell_elg_amount, 0)
            from stock_ohlcv_daily o
            left join stock_valuation_daily v
              on v.trade_date=o.trade_date and v.ts_code=o.ts_code
            left join stock_moneyflow_daily m
              on m.trade_date=o.trade_date and m.ts_code=o.ts_code
            where o.ts_code=? and o.trade_date<=?
            order by o.trade_date
            """,
            (code, as_of),
        ).fetchall()
        conn.close()
        bars = []
        for r in rows:
            raw_open = safe_float(r[3])
            raw_high = safe_float(r[4])
            raw_low = safe_float(r[5])
            raw_close = safe_float(r[6])
            qfq_close = safe_float(r[7])
            adjustment = safe_div(qfq_close, raw_close, 1.0) if raw_close > 0 and qfq_close > 0 else 1.0
            bar = PriceBar(
                date=str(r[0]),
                ts_code=str(r[1]),
                stock_name=str(r[2] or ""),
                open=raw_open * adjustment,
                high=raw_high * adjustment,
                low=raw_low * adjustment,
                close=qfq_close if qfq_close > 0 else raw_close * adjustment,
                qfq_close=qfq_close,
                raw_open=raw_open,
                raw_high=raw_high,
                raw_low=raw_low,
                raw_close=raw_close,
                pre_close=safe_float(r[8]),
                pct_chg=safe_float(r[9]) / 100.0,
                vol=safe_float(r[10]),
                amount=safe_float(r[11]),
                up_limit=safe_float(r[12]),
                down_limit=safe_float(r[13]),
                suspend_timing=str(r[14] or ""),
                turnover_rate=safe_float(r[15]),
                turnover_rate_f=safe_float(r[16]),
                volume_ratio=safe_float(r[17]),
                net_mf_amount=safe_float(r[18]),
                buy_lg_amount=safe_float(r[19]),
                sell_lg_amount=safe_float(r[20]),
                buy_elg_amount=safe_float(r[21]),
                sell_elg_amount=safe_float(r[22]),
            )
            if bar.qfq_close > 0 and bar.open > 0 and bar.high >= bar.low:
                bars.append(bar)
        audit = self.audit(bars, code, as_of)
        return bars, audit

    def audit(self, bars: List[PriceBar], code: str, as_of: str) -> Dict[str, Any]:
        blockers = []
        warnings = []
        if not bars:
            blockers.append("no_ohlcv_rows")
        if len(bars) < 260:
            warnings.append("less_than_one_trading_year")
        bad_ranges = [b.date for b in bars if b.high < b.low or b.low <= 0 or b.open <= 0 or b.close <= 0]
        if bad_ranges:
            blockers.append(f"bad_ohlc_rows:{len(bad_ranges)}")
        zero_volume = [b.date for b in bars if b.vol <= 0 and "停牌" not in b.suspend_timing]
        if len(zero_volume) > max(20, len(bars) * 0.02):
            warnings.append(f"many_zero_volume_rows:{len(zero_volume)}")
        qfq_jumps = []
        for prev, cur in zip(bars, bars[1:]):
            ret = abs(pct(cur.qfq_close, prev.qfq_close))
            raw_ret = abs(pct(cur.raw_close, prev.raw_close))
            if ret > 0.55 and raw_ret < 0.3:
                qfq_jumps.append(cur.date)
        if qfq_jumps:
            warnings.append(f"possible_qfq_discontinuity:{len(qfq_jumps)}")
        return {
            "agent": self.name,
            "ts_code": code,
            "as_of": as_of,
            "rows": len(bars),
            "start_date": bars[0].date if bars else None,
            "end_date": bars[-1].date if bars else None,
            "data_source_used": "sqlite:database/research_warehouse.db",
            "external_sources": {
                "akshare": "optional_fallback_not_used",
                "baostock": "optional_fallback_not_used",
                "tushare": "optional_fallback_not_used",
                "ifind": "optional_low_frequency_fallback_not_used",
                "wind_sql": "optional_low_frequency_fallback_not_used",
            },
            "blockers": blockers,
            "warnings": warnings,
        }


class BenchmarkContextAgent:
    name = "BenchmarkContextAgent"
    benchmark_codes = ("510050.SH", "159901.SZ", "159915.SZ")

    def build(
        self,
        db_path: Path,
        daily: List[PriceBar],
    ) -> Tuple[Dict[str, Dict[str, float]], Dict[str, Any]]:
        if not daily:
            return {}, {"agent": self.name, "status": "empty_target_history"}
        conn = sqlite3.connect(str(db_path))
        placeholders = ",".join("?" for _ in self.benchmark_codes)
        rows = conn.execute(
            f"""
            select trade_date, ts_code, close
            from etf_ohlcv_daily
            where ts_code in ({placeholders})
              and trade_date between ? and ?
              and close>0
            order by trade_date, ts_code
            """,
            tuple(self.benchmark_codes) + (daily[0].date, daily[-1].date),
        ).fetchall()
        conn.close()
        close_by_code: Dict[str, Dict[str, float]] = {
            code: {} for code in self.benchmark_codes
        }
        for trade_date, code, close in rows:
            close_by_code.setdefault(str(code), {})[str(trade_date)] = safe_float(close)
        previous_close: Dict[str, float] = {}
        history_by_code: Dict[str, List[float]] = defaultdict(list)
        synthetic_levels: List[float] = []
        synthetic_returns: List[float] = []
        contexts: Dict[str, Dict[str, float]] = {}
        level = 1.0
        stale_days = 0
        covered_days = 0
        for bar in daily:
            returns: List[float] = []
            above_ma20: List[float] = []
            for code in self.benchmark_codes:
                close = close_by_code.get(code, {}).get(bar.date)
                if close is None:
                    continue
                prior = previous_close.get(code)
                if prior and prior > 0:
                    returns.append(pct(close, prior))
                previous_close[code] = close
                history_by_code[code].append(close)
                code_history = history_by_code[code]
                if len(code_history) >= 20:
                    above_ma20.append(
                        1.0 if close >= mean(code_history[-20:]) else 0.0
                    )
            if returns:
                market_return = statistics.median(returns)
                stale_days = 0
                covered_days += 1
            else:
                market_return = 0.0
                stale_days += 1
            level *= 1.0 + max(-0.95, market_return)
            synthetic_levels.append(level)
            synthetic_returns.append(market_return)

            def trailing_return(length: int) -> float:
                if len(synthetic_levels) <= length:
                    return 0.0
                return pct(synthetic_levels[-1], synthetic_levels[-length - 1])

            high120 = max(synthetic_levels[-120:])
            contexts[bar.date] = {
                "benchmark_return_1": market_return,
                "benchmark_return_5": trailing_return(5),
                "benchmark_return_20": trailing_return(20),
                "benchmark_return_60": trailing_return(60),
                "benchmark_return_120": trailing_return(120),
                "benchmark_volatility_20": stdev(synthetic_returns[-20:]) * math.sqrt(252.0),
                "benchmark_volatility_60": stdev(synthetic_returns[-60:]) * math.sqrt(252.0),
                "benchmark_drawdown_120": pct(level, high120),
                "benchmark_breadth_up": safe_div(sum(1 for value in returns if value > 0), len(returns), 0.5),
                "benchmark_breadth_above_ma20": mean(above_ma20) if above_ma20 else 0.5,
                "benchmark_available_count": float(len(returns)),
                "benchmark_stale_days": float(stale_days),
            }
        available_codes = [
            code for code, values in close_by_code.items() if values
        ]
        return contexts, {
            "agent": self.name,
            "status": "completed" if available_codes else "no_benchmark_rows",
            "method": "causal_median_return_composite_of_predeclared_long_history_broad_etfs",
            "benchmark_codes": list(self.benchmark_codes),
            "available_codes": available_codes,
            "covered_target_days": covered_days,
            "target_day_count": len(daily),
            "coverage_ratio": safe_div(covered_days, len(daily)),
            "last_source_date_by_code": {
                code: max(values) if values else None
                for code, values in close_by_code.items()
            },
            "lookahead_guard": "each benchmark feature uses observations no later than the target date",
            "test_usage": "causal feature construction only; test labels are never used",
        }


class FrequencyAgent:
    name = "FrequencyAgent"

    @staticmethod
    def _week_key(date: str) -> str:
        d = dt.datetime.strptime(date, "%Y%m%d").date()
        year, week, _ = d.isocalendar()
        return f"{year:04d}W{week:02d}"

    @staticmethod
    def aggregate_period(xs: List[PriceBar], frequency: str) -> PriceBar:
        first = xs[0]
        last = xs[-1]
        out = PriceBar(
            date=last.date,
            ts_code=last.ts_code,
            stock_name=last.stock_name,
            open=first.open,
            high=max(x.high for x in xs),
            low=min(x.low for x in xs),
            close=last.close,
            qfq_close=last.qfq_close,
            raw_open=first.raw_open,
            raw_high=max(x.raw_high for x in xs),
            raw_low=min(x.raw_low for x in xs),
            raw_close=last.raw_close,
            pre_close=first.pre_close,
            pct_chg=pct(last.qfq_close, first.qfq_close),
            vol=sum(x.vol for x in xs),
            amount=sum(x.amount for x in xs),
            up_limit=last.up_limit,
            down_limit=last.down_limit,
            suspend_timing=last.suspend_timing,
            turnover_rate=last.turnover_rate,
            turnover_rate_f=last.turnover_rate_f,
            volume_ratio=last.volume_ratio,
            net_mf_amount=sum(x.net_mf_amount for x in xs),
            buy_lg_amount=sum(x.buy_lg_amount for x in xs),
            sell_lg_amount=sum(x.sell_lg_amount for x in xs),
            buy_elg_amount=sum(x.buy_elg_amount for x in xs),
            sell_elg_amount=sum(x.sell_elg_amount for x in xs),
        )
        return out

    def build(self, daily: List[PriceBar], frequencies: Sequence[str]) -> Dict[str, List[PriceBar]]:
        out: Dict[str, List[PriceBar]] = {}
        for freq in frequencies:
            if freq == "D":
                out[freq] = list(daily)
            elif freq == "W":
                buckets: Dict[str, List[PriceBar]] = defaultdict(list)
                order = []
                for bar in daily:
                    key = self._week_key(bar.date)
                    if key not in buckets:
                        order.append(key)
                    buckets[key].append(bar)
                out[freq] = [self.aggregate_period(buckets[k], freq) for k in order]
            elif freq == "M":
                buckets = defaultdict(list)
                order = []
                for bar in daily:
                    key = bar.date[:6]
                    if key not in buckets:
                        order.append(key)
                    buckets[key].append(bar)
                out[freq] = [self.aggregate_period(buckets[k], freq) for k in order]
            elif freq.endswith("D") and freq[:-1].isdigit():
                n = int(freq[:-1])
                rows = []
                for i in range(n - 1, len(daily)):
                    rows.append(self.aggregate_period(daily[i - n + 1 : i + 1], freq))
                out[freq] = rows
            else:
                raise ValueError(f"Unsupported frequency: {freq}")
        return out


