    trend_anchor_gate: Dict[str, Any] = {
        "status": "not_applicable",
        "reason": "passive holding does not dominate the selected champion in both train and validation",
        "test_usage": "not_used",
    }
    trend_anchor_report: Dict[str, Any] = {}
    trend_anchor_candidate_summary: Dict[str, Any] = {}
    best_train_metrics = best["backtest"]["metrics"]["train"]
    best_valid_metrics = best["backtest"]["metrics"]["valid"]
    passive_dominance = {
        "train_return_dominates": (
            safe_float(best_train_metrics.get("buy_hold_return"))
            > safe_float(best_train_metrics.get("total_return"))
        ),
        "valid_return_dominates": (
            safe_float(best_valid_metrics.get("buy_hold_return"))
            > safe_float(best_valid_metrics.get("total_return"))
        ),
    }
    if all(passive_dominance.values()):
        champion_position_by_date = {
            str(row.get("date")): safe_float(row.get("position"))
            for row in best["backtest"].get("nav", [])
        }
        trend_anchor_targets: Dict[str, float] = {}
        trend_anchor_scores: Dict[str, Dict[str, Any]] = {}
        for bar in daily:
            champion_position = safe_float(
                champion_position_by_date.get(bar.date)
            )
            continuous_target = 0.5 * champion_position + 0.5
            target = min(
                POSITION_LEVELS,
                key=lambda value: abs(value - continuous_target),
            )
            trend_anchor_targets[bar.date] = target
            trend_anchor_scores[bar.date] = {
                "score": 2.0 * target - 1.0,
                "continuous_target": continuous_target,
                "quantized_target": target,
                "decision_date": True,
                "bull_score": target,
                "bear_score": 1.0 - target,
                "conflict_ratio": safe_div(
                    min(target, 1.0 - target),
                    max(target, 1.0 - target, 1e-9),
                ),
                "leader_weights": [
                    {
                        "name": str(best["spec"]["name"]),
                        "family": "selected_champion",
                        "weight": 0.5,
                    },
                    {
                        "name": "长期趋势持有",
                        "family": "passive_trend_anchor",
                        "weight": 0.5,
                    },
                ],
                "regime": {},
                "split": split_by_date.get(bar.date),
            }
        trend_anchor_report = {
            "enabled": True,
            "agent": "TrainValidDominantTrendAnchorAgent",
            "method": (
                "predeclared_equal_weight_selected_champion_and_passive_"
                "holding_anchor_quantized_to_five_positions"
            ),
            "base_champion": best["spec"]["name"],
            "passive_dominance": passive_dominance,
            "champion_weight": 0.5,
            "passive_weight": 0.5,
            "position_grid": list(POSITION_LEVELS),
            "selection_policy": (
                "candidate exists only when passive holding strictly exceeds the "
                "selected champion total return in both train and validation"
            ),
            "test_usage": "sealed_not_used_for_candidate_creation_or_selection",
        }
        trend_anchor_agent = DirectPositionSignalAgent(
            trend_anchor_targets,
            trend_anchor_scores,
            trend_anchor_report,
        )
