_FACTOR_UI_JS = r"""
let factorEnvelope = null;
let factorPollTimer = null;
let factorBootstrapped = false;
let factorStocksLoaded = false;
let factorSelectionInitialized = false;
let factorStockPayload = null;

function setProduct(name) {
  const factor = name === "factor";
  $("product_factor").classList.toggle("active", factor);
  $("product_kline").classList.toggle("active", !factor);
  $("factor_area").style.display = factor ? "block" : "none";
  $("kline_area").style.display = factor ? "none" : "block";
  if (factor) renderFactorSelection();
  else if (lastJob) { drawKline(lastJob.summary || {}); drawEquity(lastJob.summary || {}); }
}

function switchFactorView(name) {
  document.querySelectorAll(".factor-tab").forEach(x => x.classList.toggle("active", x.dataset.factorView === name));
  document.querySelectorAll(".factor-view").forEach(x => x.classList.remove("active"));
  const target = $("factor_view_" + name);
  if (target) target.classList.add("active");
  if (name === "validation") renderFactorSelection();
  if (name === "stock") renderFactorRankings();
}

function factorBlock() {
  const result = factorEnvelope && factorEnvelope.result;
  if (!result || !result.results) return null;
  const universe = $("factor_universe").value || "ALL_A";
  const frequency = $("factor_frequency").value || "W";
  return result.results[universe] && result.results[universe][frequency] || null;
}

function renderFactorJob(job) {
  job = job || {};
  const map = {idle:"尚未运行", queued:"排队中", running:"运行中", done:"已完成", error:"失败"};
  const statusText = `${map[job.status] || job.status || "未知"}｜${job.progress_message || ""}`;
  $("factor_status").textContent = statusText;
  $("factor_status").className = job.status === "error" ? "bad" : "";
  $("factor_progress_fill").style.width = `${Math.max(0, Math.min(100, Number(job.progress_percent || 0)))}%`;
  $("factor_elapsed").textContent = job.elapsed_seconds != null ? `耗时 ${sig(job.elapsed_seconds)} 秒` : "";
  $("factor_run").disabled = job.status === "queued" || job.status === "running";
}

async function loadFactorStudy() {
  const out = await jsonFetch("/api/factor-study");
  factorEnvelope = out;
  renderFactorJob(out.job || {});
  if (out.result) renderFactorAll();
  else $("factor_matrix").innerHTML = `<div class="empty-state">暂无成功缓存，点击“运行因子研究”后后台计算。</div>`;
  const statusName = (out.job || {}).status;
  if (statusName === "queued" || statusName === "running") {
    if (!factorPollTimer) factorPollTimer = setInterval(() => loadFactorStudy().catch(e => { $("factor_status").textContent = e.message; }), 4000);
  } else if (factorPollTimer) {
    clearInterval(factorPollTimer);
    factorPollTimer = null;
  }
}

async function loadFactorStocks() {
  if (factorStocksLoaded) return;
  const out = await jsonFetch("/api/stocks?limit=6000");
  const rows = out.stocks || [];
  $("factor_stock").innerHTML = rows.map(row => `<option value="${esc(row.code)}">${esc(row.code)}｜${esc(row.name || "")}</option>`).join("");
  factorStocksLoaded = true;
}

function renderFactorAll() {
  const result = factorEnvelope.result || {};
  $("factor_name").textContent = `${result.factor_name || "横截面因子"}｜公式与构造逻辑`;
  if (!factorSelectionInitialized) {
    const ranked = (result.matrix || []).slice().sort((a,b) => Number(b.passed)-Number(a.passed) || Number(b.score||0)-Number(a.score||0));
    if (ranked.length) {
      $("factor_universe").value = ranked[0].universe;
      $("factor_frequency").value = ranked[0].frequency;
      $("factor_stock_frequency").value = ranked[0].frequency;
    }
    factorSelectionInitialized = true;
  }
  renderFactorMatrix(result);
  renderFactorIntegrity(result);
  renderFactorSelection();
  renderFactorRankings();
}

function renderFactorMatrix(result) {
  const rows = result.matrix || [];
  if (!rows.length) {
    $("factor_matrix").innerHTML = `<div class="empty-state">当前结果没有三域四频矩阵。</div>`;
    return;
  }
  const body = rows.map(row => `<tr data-universe="${esc(row.universe)}" data-frequency="${esc(row.frequency)}"><td>${esc(row.universe_cn)}</td><td>${esc(row.frequency_cn)}</td><td>${num(row.train_rank_ic)}</td><td>${num(row.valid_rank_ic)}</td><td>${num(row.test_rank_ic)}</td><td>${pct(row.test_excess_annual_return)}</td><td>${num(row.test_sharpe)}</td><td>${pct(row.test_max_drawdown)}</td><td>${num(row.score)}</td><td class="${row.passed ? "result-pass" : "result-fail"}">${row.passed ? "通过" : "未通过"}</td></tr>`).join("");
  $("factor_matrix").className = "matrix-wrap";
  $("factor_matrix").innerHTML = `<table class="factor-table"><thead><tr><th>股票域</th><th>频率</th><th>训练RankIC</th><th>验证RankIC</th><th>测试RankIC</th><th>测试超额年化</th><th>测试夏普</th><th>最大回撤</th><th>综合分</th><th>结论</th></tr></thead><tbody>${body}</tbody></table>`;
}

function renderFactorIntegrity(result) {
  const labels = {
    signal_uses_close_or_earlier:"信号仅使用当日收盘前数据",
    execution_is_next_trade_open:"下一交易日开盘执行",
    financials_are_visible_date_asof:"财务数据按披露可见日",
    membership_is_signal_date_asof:"成分股按信号日历史快照",
    test_not_used_for_formula_or_direction:"封存测试不参与公式选择",
    boundary_crossing_labels_are_purged:"跨分段收益标签已隔离",
    ranker_trained_without_test_labels:"LambdaRank未使用测试标签",
    factor_timing_uses_one_period_reporting_lag:"状态判断严格滞后一周期"
  };
  const integrity = result.integrity || {};
  $("factor_integrity").innerHTML = Object.entries(labels).map(([key,label]) => `<div class="check-item ${integrity[key] ? "pass" : "fail"}">${integrity[key] ? "通过" : "未通过"}｜${label}</div>`).join("");
}

function renderFactorSelection() {
  const block = factorBlock();
  if (!block) return;
  $("factor_stock_frequency").value = block.frequency;
  const diagnostics = block.diagnostics || {};
  const policy = diagnostics.strategy_policy || {};
  const mode = policy.timing_enabled ? "严格滞后状态翻转" : "静态正向排序";
  $("factor_selection_note").textContent = `${block.universe_cn}｜${block.frequency_cn}｜${mode}｜目标宽度 ×${sig(policy.target_multiplier || 1)}｜尾部跳过 ${pct(policy.skip_fraction || 0)}｜缓冲 ×${sig(policy.buffer_multiple || 1)}｜持久性 ${pct(policy.persistence_ratio || 0)}｜成本 ${pct(diagnostics.cost_rate_per_turnover || 0)}/单边换手`;
  renderFactorScore(block);
  renderFactorSplits(block);
  renderFactorGroups(block);
  renderFactorHeatmap(block.annual || []);
  renderFactorComponents(block.score || {});
  renderFactorChecks(block.score || {});
  drawFactorCharts(block);
  renderFactorRankings();
}

function renderFactorScore(block) {
  const score = block.score || {};
  const checks = score.checks || {};
  const passed = Object.values(checks).filter(Boolean).length;
  const total = Object.keys(checks).length;
  const policy = ((block.diagnostics || {}).strategy_policy) || {};
  const mode = policy.timing_enabled ? "滞后状态翻转" : "静态正向排序";
  $("factor_score_head").innerHTML = `<div class="score-total"><span>综合评分｜${esc(score.grade || "-")}</span><strong>${num(score.score)} / 100</strong><div class="${score.passed ? "result-pass" : "result-fail"}">${score.passed ? "全部检验通过" : "存在未通过检验"}</div></div><div class="check-grid"><div class="check-item"><b>通过项</b><div>${passed} / ${total}</div></div><div class="check-item"><b>封存测试RankIC</b><div>${num(((block.metrics || {}).test || {}).rank_ic)}</div></div><div class="check-item"><b>封存测试超额</b><div>${pct(((block.metrics || {}).test || {}).excess_annual_return)}</div></div><div class="check-item"><b>执行模式</b><div>${mode}</div></div><div class="check-item"><b>目标持仓宽度</b><div>×${sig(policy.target_multiplier || 1)}</div></div></div>`;
}

function renderFactorSplits(block) {
  const names = {train:"训练期", valid:"验证期", test:"封存测试期", full:"全窗口"};
  const metrics = block.metrics || {};
  $("factor_split_cards").innerHTML = ["train","valid","test","full"].map(key => {
    const m = metrics[key] || {};
    return `<div class="split-card"><b>${names[key]}</b><strong>RankIC ${num(m.rank_ic)}</strong><small>超额年化 ${pct(m.excess_annual_return)}｜夏普 ${num(m.sharpe)}<br>最大回撤 ${pct(m.max_drawdown)}｜覆盖率 ${pct(m.coverage)}</small></div>`;
  }).join("");
}

function renderFactorGroups(block) {
  const groups = (((block.metrics || {}).full || {}).group_returns) || [];
  if (groups.length !== 5) {
    $("factor_groups").innerHTML = `<div class="empty-state">当前频率样本不足，尚不能形成五组稳定统计。</div>`;
    return;
  }
  const maxAbs = Math.max(...groups.map(x => Math.abs(Number(x || 0))), 1e-8);
  $("factor_groups").innerHTML = groups.map((value,index) => `<div class="group-row"><span>第${index+1}组</span><div class="group-track"><div class="group-fill ${Number(value)<0 ? "negative" : ""}" style="width:${Math.max(2,Math.abs(Number(value))*100/maxAbs)}%"></div></div><b>${pct(value)}</b></div>`).join("");
}

function heatColor(value, scale) {
  const n = Math.max(-1, Math.min(1, Number(value || 0) / scale));
  if (n >= 0) return `rgba(39,107,88,${0.10 + 0.72*n})`;
  return `rgba(157,59,59,${0.10 + 0.60*Math.abs(n)})`;
}

function renderFactorHeatmap(rows) {
  if (!rows.length) { $("factor_heatmap").innerHTML = `<div class="empty-state">暂无年度统计</div>`; return; }
  const head = `<div class="muted">年份</div><div class="muted">RankIC</div><div class="muted">超额收益</div><div class="muted">覆盖率</div>`;
  const body = rows.map(row => `<b>${esc(row.year)}</b><div class="heat-cell" style="background:${heatColor(row.rank_ic,.08)}">${num(row.rank_ic)}</div><div class="heat-cell" style="background:${heatColor(row.excess_return,.20)}">${pct(row.excess_return)}</div><div class="heat-cell" style="background:${heatColor(Number(row.coverage)-.7,.30)}">${pct(row.coverage)}</div>`).join("");
  $("factor_heatmap").innerHTML = `<div class="heat-table">${head}${body}</div>`;
}

function renderFactorComponents(score) {
  const caps = {"训练证据":20,"验证稳定":20,"封存测试":20,"组合收益":15,"分组单调":10,"风险成本":10,"数据完整":5};
  $("factor_components").innerHTML = Object.entries(score.components || {}).map(([name,value]) => `<div class="component-row"><span>${esc(name)}</span><div class="component-track"><div class="component-fill" style="width:${Math.max(0,Math.min(100,Number(value||0)*100/(caps[name]||20)))}%"></div></div><b>${num(value)}</b></div>`).join("");
}

function renderFactorChecks(score) {
  $("factor_checks").innerHTML = Object.entries(score.checks || {}).map(([name,passed]) => `<div class="check-item ${passed ? "pass" : "fail"}">${passed ? "通过" : "未通过"}｜${esc(name)}</div>`).join("");
}

function canvasFrame(id) {
  const canvas = $(id);
  if (!canvas) return null;
  const rect = canvas.getBoundingClientRect();
  const width = Math.max(320, Math.round(rect.width || canvas.clientWidth || 700));
  const height = Math.max(220, Math.round(rect.height || canvas.clientHeight || 290));
  const dpr = Math.min(window.devicePixelRatio || 1, 2);
  canvas.width = Math.round(width*dpr); canvas.height = Math.round(height*dpr);
  const ctx = canvas.getContext("2d"); ctx.setTransform(dpr,0,0,dpr,0,0); ctx.clearRect(0,0,width,height);
  return {canvas,ctx,width,height};
}

function drawMulti(id, rows, specs, percentAxis=false) {
  const frame = canvasFrame(id); if (!frame) return;
  const {ctx,width,height} = frame; const left=52,right=16,top=20,bottom=34; const w=width-left-right,h=height-top-bottom;
  if (!rows || rows.length < 2) { ctx.fillStyle="#667085"; ctx.font="12px Arial"; ctx.fillText("暂无可绘制数据",left,top+28); return; }
  const values=[]; rows.forEach(row => specs.forEach(spec => { const v=Number(row.values[spec.index]); if(Number.isFinite(v)) values.push(v); }));
  if (!values.length) return;
  let ymin=Math.min(...values), ymax=Math.max(...values); if (ymin===ymax) { ymin-=1; ymax+=1; }
  const pad=(ymax-ymin)*.10; ymin-=pad; ymax+=pad;
  const x=i=>left+i*w/Math.max(rows.length-1,1); const y=v=>top+(ymax-v)*h/(ymax-ymin);
  const splitColors={train:"rgba(47,95,159,.035)",valid:"rgba(39,107,88,.045)",test:"rgba(183,121,31,.045)"};
  let start=0; for(let i=1;i<=rows.length;i++){ if(i===rows.length || rows[i].split!==rows[start].split){ ctx.fillStyle=splitColors[rows[start].split]||"transparent"; ctx.fillRect(x(start),top,Math.max(1,x(Math.min(i,rows.length-1))-x(start)),h); start=i; } }
  ctx.strokeStyle="#e3e7ee"; ctx.lineWidth=1; ctx.fillStyle="#667085"; ctx.font="11px Arial";
  for(let g=0;g<5;g++){ const v=ymin+(ymax-ymin)*g/4; const yy=y(v); ctx.beginPath(); ctx.moveTo(left,yy); ctx.lineTo(width-right,yy); ctx.stroke(); ctx.fillText(percentAxis ? pct(v) : num(v),4,yy+4); }
  specs.forEach(spec => { ctx.strokeStyle=spec.color; ctx.lineWidth=2; ctx.beginPath(); let begun=false; rows.forEach((row,i)=>{ const v=Number(row.values[spec.index]); if(!Number.isFinite(v)){begun=false;return;} if(!begun){ctx.moveTo(x(i),y(v));begun=true;}else ctx.lineTo(x(i),y(v)); }); ctx.stroke(); });
  const ticks=Math.min(5,rows.length); ctx.fillStyle="#667085"; for(let t=0;t<ticks;t++){ const i=Math.round(t*(rows.length-1)/Math.max(ticks-1,1)); const label=String(rows[i].date||""); ctx.fillText(label.slice(0,4)+"-"+label.slice(4,6),Math.max(left-8,Math.min(width-58,x(i)-18)),height-10); }
}

function drawFactorCharts(block) {
  const curve=(block.curve||[]).map(row=>({date:row[0],values:[row[1],row[2],row[3],row[4],row[5],row[6]],split:row[7]}));
  drawMulti("factor_nav_canvas",curve,[{index:0,color:"#2f5f9f"},{index:1,color:"#7a8089"},{index:2,color:"#276b58"}],false);
  drawMulti("factor_drawdown_canvas",curve,[{index:3,color:"#2f5f9f"},{index:4,color:"#7a8089"},{index:5,color:"#9d3b3b"}],true);
  const source=block.ic_series||[]; const rolling=[]; const windowSize=Math.max(4,Math.min(12,Math.round(source.length/16)||4));
  source.forEach((row,index)=>{ const part=source.slice(Math.max(0,index-windowSize+1),index+1).map(x=>Number(x[1]||0)); rolling.push(part.reduce((a,b)=>a+b,0)/part.length); });
  const icRows=source.map((row,index)=>({date:row[0],values:[Number(row[1]||0),rolling[index]],split:row[2]}));
  drawMulti("factor_ic_canvas",icRows,[{index:0,color:"#2f5f9f"},{index:1,color:"#276b58"}],false);
}

function rankTable(rows) {
  if (!rows || !rows.length) return `<div class="empty-state">暂无排名</div>`;
  const body=rows.map(row=>`<tr data-code="${esc(row.ts_code)}"><td>${row.rank}</td><td>${esc(row.ts_code)}｜${esc(row.stock_name)}</td><td>${esc(row.industry_name)}</td><td>${num(row.factor_score)}</td><td>${num(row.low_crowding)}</td><td>${num(row.reversal)}</td><td>${num(row.value)}</td><td>${num(row.trend)}</td></tr>`).join("");
  return `<table class="factor-table"><thead><tr><th>#</th><th>个股</th><th>行业</th><th>因子</th><th>低拥挤</th><th>短期反转</th><th>价值</th><th>过度延伸</th></tr></thead><tbody>${body}</tbody></table>`;
}

function renderFactorRankings() {
  const block=factorBlock(); if(!block) return;
  $("factor_top10").innerHTML=rankTable(block.top10||[]);
  $("factor_bottom10").innerHTML=rankTable(block.bottom10||[]);
  const preferred=(block.top10||[])[0];
  if(preferred && $("factor_stock").options.length && !$("factor_stock").value) $("factor_stock").value=preferred.ts_code;
}

async function loadFactorStockSeries(code) {
  code=code || $("factor_stock").value; if(!code) return;
  const block=factorBlock();
  const universe=(block&&block.universe)||$("factor_universe").value||"ALL_A";
  const frequency=$("factor_stock_frequency").value||"W";
  const out=await jsonFetch(`/api/factor-study/stock?code=${encodeURIComponent(code)}&frequency=${encodeURIComponent(frequency)}&universe=${encodeURIComponent(universe)}`);
  factorStockPayload=out;
  $("factor_stock_title").textContent=`${out.ts_code||code} ${out.stock_name||""}｜${out.universe_cn||universe} ${out.frequency_cn||frequency}因子、仓位与复权价格`;
  renderFactorStockMetrics(out);
  drawFactorStock(out.series||[],out.signal_policy||{});
  drawFactorStockStrategy(out.strategy_curve||[]);
}

function renderFactorStockMetrics(out) {
  const policy=out.signal_policy||{};
  const hasCurve=(out.strategy_curve||[]).length>1;
  const scope=String(policy.quality_scope||"按信号日可见范围执行质量与可交易约束").replace(/[。；;,.，]+$/g,"");
  $("factor_stock_note").textContent=`${out.universe_cn||policy.universe_cn||"股票域"}｜${out.frequency_cn||policy.frequency_cn||"频率"}｜买入分位 ≥ ${num(policy.entry_threshold)}｜退出分位 ≤ ${num(policy.exit_threshold)}｜单边换手成本 ${pct(policy.cost_rate_per_turnover||0)}。${policy.execution||"信号确认后下一交易日开盘执行"}；${scope}${hasCurve?"。":"；当前股票在本窗口没有足够的可执行策略区间。"}`;
  const metrics=out.strategy_metrics||{};
  const labels={train:"训练期",valid:"验证期",test:"封存测试期",full:"全窗口"};
  if(!Object.keys(metrics).length){$("factor_stock_metrics").innerHTML=`<div class="empty-state">当前个股没有策略指标。</div>`;return;}
  $("factor_stock_metrics").innerHTML=["train","valid","test","full"].map(key=>{
    const m=metrics[key]||{};
    return `<div class="split-card"><b>${labels[key]}</b><strong>策略年化 ${pct(m.annual_return)}</strong><small>买入持有 ${pct(m.buy_hold_annual_return)}｜超额 ${pct(m.excess_annual_return)}<br>夏普 ${num(m.sharpe)}｜最大回撤 ${pct(m.max_drawdown)}<br>持仓占比 ${pct(m.invested_ratio)}｜交易 ${sig(m.trade_count||0)} 次｜有效期数 ${sig(m.periods||0)}</small></div>`;
  }).join("");
}

function factorStockSplit(date) {
  const split=((factorEnvelope||{}).result||{}).split||{};
  for(const key of ["train","valid","test"]){const row=split[key]||{};if(row.start&&row.end&&String(date)>=String(row.start)&&String(date)<=String(row.end))return key;}
  return "full";
}

function drawFactorStock(series,policy) {
  const frame=canvasFrame("factor_stock_canvas"); if(!frame) return;
  const {ctx,width,height}=frame; const left=52,right=58,top=20,bottom=34,w=width-left-right,h=height-top-bottom;
  if(!series||series.length<2){ctx.fillStyle="#667085";ctx.font="12px Arial";ctx.fillText("当前个股没有可用因子时序",left,top+28);return;}
  const scores=series.map(x=>Number(x[1])).filter(Number.isFinite), prices=series.map(x=>Number(x[2])).filter(Number.isFinite);
  const entry=Number(policy.entry_threshold),exit=Number(policy.exit_threshold); if(Number.isFinite(entry))scores.push(entry);if(Number.isFinite(exit))scores.push(exit);
  let smin=Math.min(...scores),smax=Math.max(...scores),pmin=Math.min(...prices),pmax=Math.max(...prices); if(smin===smax){smin-=.1;smax+=.1;} if(pmin===pmax){pmin-=1;pmax+=1;}
  const spad=(smax-smin)*.07; smin-=spad;smax+=spad; const ppad=(pmax-pmin)*.05;pmin-=ppad;pmax+=ppad;
  const x=i=>left+i*w/Math.max(series.length-1,1), ys=v=>top+(smax-v)*h/(smax-smin), yp=v=>top+(pmax-v)*h/(pmax-pmin);
  const splitColors={train:"rgba(47,95,159,.035)",valid:"rgba(39,107,88,.045)",test:"rgba(183,121,31,.045)"};
  let segment=0;for(let i=1;i<=series.length;i++){if(i===series.length||factorStockSplit(series[i][0])!==factorStockSplit(series[segment][0])){ctx.fillStyle=splitColors[factorStockSplit(series[segment][0])]||"transparent";ctx.fillRect(x(segment),top,Math.max(1,x(Math.min(i,series.length-1))-x(segment)),h);segment=i;}}
  series.forEach((row,i)=>{if(Number(row[3])>0){ctx.fillStyle="rgba(39,107,88,.075)";ctx.fillRect(x(i),top,Math.max(2,x(Math.min(i+1,series.length-1))-x(i)),h);}});
  ctx.strokeStyle="#e3e7ee";ctx.fillStyle="#667085";ctx.font="11px Arial"; for(let g=0;g<5;g++){const yy=top+h*g/4;ctx.beginPath();ctx.moveTo(left,yy);ctx.lineTo(width-right,yy);ctx.stroke();ctx.fillText(num(smax-(smax-smin)*g/4),5,yy+4);ctx.fillText(num(pmax-(pmax-pmin)*g/4),width-right+5,yy+4);}
  [[1,"#276b58",ys],[2,"#2f5f9f",yp]].forEach(([idx,color,yfn])=>{ctx.strokeStyle=color;ctx.lineWidth=2;ctx.beginPath();let begun=false;series.forEach((row,i)=>{const v=Number(row[idx]);if(!Number.isFinite(v)){begun=false;return;}const yy=yfn(v);if(!begun){ctx.moveTo(x(i),yy);begun=true;}else ctx.lineTo(x(i),yy);});ctx.stroke();});
  [[entry,"#4f9b70"],[exit,"#b15a52"]].forEach(([value,color])=>{if(!Number.isFinite(value))return;ctx.save();ctx.strokeStyle=color;ctx.lineWidth=1.2;ctx.setLineDash([5,4]);ctx.beginPath();ctx.moveTo(left,ys(value));ctx.lineTo(width-right,ys(value));ctx.stroke();ctx.restore();});
  series.forEach((row,i)=>{const action=String(row[4]||"");const score=Number(row[1]);if(!Number.isFinite(score)||!(action==="买入"||action==="卖出"))return;const xx=x(i),yy=ys(score);ctx.fillStyle=action==="买入"?"#4f9b70":"#b15a52";ctx.beginPath();if(action==="买入"){ctx.arc(xx,yy,4.5,0,Math.PI*2);}else{ctx.moveTo(xx,yy+5);ctx.lineTo(xx-5,yy-4);ctx.lineTo(xx+5,yy-4);ctx.closePath();}ctx.fill();});
  const ticks=Math.min(5,series.length);for(let t=0;t<ticks;t++){const i=Math.round(t*(series.length-1)/Math.max(ticks-1,1));const d=String(series[i][0]);ctx.fillStyle="#667085";ctx.fillText(d.slice(0,4)+"-"+d.slice(4,6),Math.max(left-8,Math.min(width-60,x(i)-18)),height-10);}
}

function drawFactorStockStrategy(curve) {
  const rows=(curve||[]).map(row=>({date:row[0],values:[row[1],row[2],row[3],row[4]],split:row[8]}));
  drawMulti("factor_stock_nav_canvas",rows,[{index:0,color:"#276b58"},{index:1,color:"#7a8089"}],false);
  drawMulti("factor_stock_drawdown_canvas",rows,[{index:2,color:"#276b58"},{index:3,color:"#9d3b3b"}],true);
}
function bootstrapFactorArea() {
  if (factorBootstrapped || document.body.classList.contains("auth-locked")) return;
  factorBootstrapped=true;
  Promise.all([loadFactorStudy(),loadFactorStocks()]).then(()=>{renderFactorRankings(); const block=factorBlock(); const code=block&&block.top10&&block.top10[0]&&block.top10[0].ts_code; if(code){$("factor_stock").value=code;loadFactorStockSeries(code).catch(()=>{});}}).catch(e=>{$("factor_status").textContent=e.message;$("factor_status").className="bad";});
}

$("product_factor").onclick=()=>setProduct("factor");
$("product_kline").onclick=()=>setProduct("kline");
document.querySelectorAll(".factor-tab").forEach(btn=>btn.onclick=()=>switchFactorView(btn.dataset.factorView));
$("factor_universe").onchange=renderFactorSelection;
$("factor_frequency").onchange=renderFactorSelection;
$("factor_stock_load").onclick=()=>loadFactorStockSeries().catch(e=>{$("factor_stock_title").textContent=e.message;});
$("factor_stock").onchange=()=>loadFactorStockSeries().catch(()=>{});
$("factor_stock_frequency").onchange=()=>loadFactorStockSeries().catch(()=>{});
$("factor_run").onclick=async()=>{try{$("factor_run").disabled=true;await jsonFetch("/api/factor-study",{method:"POST",headers:headers(),body:JSON.stringify({force:$("factor_force").value==="1"})});await loadFactorStudy();}catch(e){$("factor_status").textContent=e.message;$("factor_status").className="bad";$("factor_run").disabled=false;await loadFactorStudy().catch(()=>{});}};
$("factor_matrix").addEventListener("click",event=>{const row=event.target.closest("tr[data-universe]");if(!row)return;$("factor_universe").value=row.dataset.universe;$("factor_frequency").value=row.dataset.frequency;switchFactorView("validation");});
[$("factor_top10"),$("factor_bottom10")].forEach(root=>root.addEventListener("click",event=>{const row=event.target.closest("tr[data-code]");if(!row)return;$("factor_stock").value=row.dataset.code;switchFactorView("stock");loadFactorStockSeries(row.dataset.code).catch(()=>{});}));
new MutationObserver(bootstrapFactorArea).observe(document.body,{attributes:true,attributeFilter:["class"]});
window.addEventListener("resize",()=>{if(factorEnvelope&&factorEnvelope.result){renderFactorSelection();if(factorStockPayload){drawFactorStock(factorStockPayload.series||[],factorStockPayload.signal_policy||{});drawFactorStockStrategy(factorStockPayload.strategy_curve||[]);}}});
setTimeout(bootstrapFactorArea,0);
"""
def _modern_index_html_v3(self) -> str:
    page = _modern_index_html_v2(self)
    page = page.replace("<title>个股K线记忆学习Agent</title>", "<title>量化因子与K线学习Agent</title>", 1)
    page = page.replace("<h1>个股K线记忆学习Agent</h1>", "<h1>量化因子与K线学习Agent</h1>", 1)
    page = page.replace("Kline Learning Login", "Quant Research Login", 1)
    page = page.replace("  </style>", _FACTOR_UI_CSS + "\n  </style>", 1)
    page = page.replace('<div id="app_area">', '<div id="app_area">\n' + _FACTOR_UI_HTML, 1)
    closing = "  </div>\n</main>"
    head, separator, tail = page.rpartition(closing)
    if separator:
        page = head + "  </div>\n  </div>\n</main>" + tail
    page = page.replace(
        'const BASE_PATH = (location.pathname === "/kline" || location.pathname.startsWith("/kline/")) ? "/kline" : "";',
        'const BASE_PATH = ["/quant-agent","/kline"].find(prefix => location.pathname === prefix || location.pathname.startsWith(prefix + "/")) || "";',
        1,
    )
    page = page.replace("</script>", _FACTOR_UI_JS + "\n</script>", 1)
    return page
KlinePublicHandler.index_html = _modern_index_html_v3


def serve_public_agent(
    db: Path,
    host: str,
    port: int,
    output_root: Path,
    cost_rate: float,
    max_gpt_batches: int,
    max_workers: int,
) -> None:
    output_root.mkdir(parents=True, exist_ok=True)
    token = ""
    state = KlinePublicServiceState(
        db=Path(db),
        output_root=Path(output_root),
        cost_rate=cost_rate,
        max_gpt_batches=max_gpt_batches,
        max_workers=max_workers,
        token=token,
    )
    server = ThreadingHTTPServer((host, port), KlinePublicHandler)
    server.kline_state = state  # type: ignore[attr-defined]
    print(json.dumps({
        "agent": "个股K线记忆学习Agent",
        "mode": "public_http_service",
        "host": host,
        "port": port,
        "db": str(db),
        "output_root": str(output_root),
        "auth_required": True,
        "max_workers": state.max_workers,
    }, ensure_ascii=False, indent=2), flush=True)
    server.serve_forever()


def main() -> None:
    parser = argparse.ArgumentParser(description="个股K线记忆学习Agent")
    parser.add_argument("--db", default=str(DEFAULT_DB), help="Path to research_warehouse.db")
    parser.add_argument("--code", help="A-share ts_code, for example 000001.SZ")
    parser.add_argument("--as-of", default="latest", help="YYYYMMDD or latest")
    parser.add_argument("--frequencies", default=",".join(ALL_FREQUENCIES), help="Comma-separated frequencies, default D,W,M,3D,5D,10D,20D,60D,120D")
    parser.add_argument("--cost-rate", type=float, default=DEFAULT_COST_RATE)
    parser.add_argument("--holding-days", type=int, default=DEFAULT_HOLDING_DAYS, choices=FORWARD_HORIZONS, help="Primary holding/evaluation window")
    parser.add_argument("--position-profile", default="balanced", choices=sorted(POSITION_PROFILES), help="Position sizing profile")
    parser.add_argument("--cohort-mode", default="hybrid", choices=COHORT_MODES, help="Same-category learning scope")
    parser.add_argument("--require-gpt", action="store_true", help="Fail if AI_ROUTER_API_KEY/OPENAI_API_KEY is not configured")
    parser.add_argument("--gpt-full-history", action="store_true", help="Send all compressed event-card batches to GPT")
    parser.add_argument("--no-gpt", action="store_true", help="Disable GPT calls for local validation/smoke tests")
    parser.add_argument("--max-gpt-batches", type=int, default=0, help="0 means no cap unless --gpt-full-history is false and key is present")
    parser.add_argument("--write-db", action="store_true", help="Write learned scores/rules to kline_feature_daily")
    parser.add_argument("--out-dir", default=None, help="Output directory. Defaults to output/kline_memory_learning/code/as_of")
    parser.add_argument("--no-artifacts", action="store_true", help="Do not write result files; useful for smoke tests")
    parser.add_argument("--serve", action="store_true", help="Run public HTTP service mode")
    parser.add_argument("--host", default="127.0.0.1", help="HTTP service host, default 127.0.0.1")
    parser.add_argument("--port", type=int, default=8877, help="HTTP service port, default 8877")
    parser.add_argument("--service-output-root", default=str(DEFAULT_PROJECT_ROOT / "output" / "kline_memory_learning" / "service_jobs"), help="Output root for HTTP service jobs")
    parser.add_argument("--service-max-workers", type=int, default=1, help="Max concurrent public service jobs")
    args = parser.parse_args()
    if args.serve:
        serve_public_agent(
            db=Path(args.db),
            host=args.host,
            port=args.port,
            output_root=Path(args.service_output_root),
            cost_rate=args.cost_rate,
            max_gpt_batches=args.max_gpt_batches,
            max_workers=args.service_max_workers,
        )
        return
    if not args.code:
        parser.error("--code is required unless --serve is used")
    frequencies = [x.strip() for x in args.frequencies.split(",") if x.strip()]
    if args.max_gpt_batches == 0 and not args.gpt_full_history:
        args.max_gpt_batches = 6
    result = analyze(
        db=Path(args.db),
        code=args.code,
        as_of=None if args.as_of == "latest" else args.as_of,
        frequencies=frequencies,
        cost_rate=args.cost_rate,
        holding_days=args.holding_days,
        position_profile=args.position_profile,
        require_gpt=args.require_gpt,
        gpt_full_history=args.gpt_full_history,
        max_gpt_batches=args.max_gpt_batches,
        use_gpt=not args.no_gpt,
        cohort_mode=args.cohort_mode,
        write_db=args.write_db,
        output_dir=Path(args.out_dir) if args.out_dir else None,
        write_artifact_files=not args.no_artifacts,
    )
    print(json.dumps({
        "agent": result["agent"],
        "version": result["version"],
        "ts_code": result["ts_code"],
        "as_of": result["as_of"],
        "data_rows": result["data_audit"]["rows"],
        "frequency_coverage": result["frequency_coverage"],
        "rule_status_counts": result["rule_status_counts"],
        "selected_signal_chain": result.get("regime_context", {}).get("strategy_variant_selection", {}).get("selected_name"),
        "regime_policy_states": result.get("regime_context", {}).get("regime_policy", {}).get("states", {}),
        "latest_signal": {
            "score": result["latest_signal"]["score"],
            "action": result["latest_signal"]["action"],
            "target_position": result["latest_signal"]["target_position"],
            "target_position_instruction": result["latest_signal"]["target_position_instruction"],
        },
        "backtest_metrics": result["backtest_metrics"],
        "strategy_variant_diagnostics": [
            {
                "name": row.get("name"),
                "selection_score": (row.get("selection") or {}).get("selection_score"),
                "quality_gate_pass": (row.get("selection") or {}).get("quality_gate_pass"),
                "provisional_tradability_gate_pass": (row.get("selection") or {}).get("provisional_tradability_gate_pass"),
                "reliability_status": (row.get("selection") or {}).get("reliability_status"),
                "penalties": (row.get("selection") or {}).get("penalties", []),
                "quality_gate_reasons": (row.get("selection") or {}).get("quality_gate_reasons", []),
                "train": row.get("train", {}),
                "valid": row.get("valid", {}),
                "test_report_only": row.get("test_report_only", {}),
                "valid_trade_stats": row.get("valid_trade_stats", {}),
            }
            for row in (
                result.get("regime_context", {})
                .get("strategy_variant_selection", {})
                .get("variants", [])
            )
        ],
        "gpt_status": result["gpt_review"]["status"],
        "artifact_paths": result.get("artifact_paths", {}),
    }, ensure_ascii=False, indent=2))


if __name__ == "__main__":
    main()
